Certainly! Below is an example of how to implement a function-calling round trip using the OpenAI SDK in Python. This example includes setting up the OpenAI client, defining a local stub for the `lookup_stock` function, sending the tool result back to the model, and printing the model's final answer.

First, make sure you have the OpenAI Python package installed:

```bash
pip install openai
```

Next, here is the complete code:

```python
import openai

# Set up your OpenAI API key
openai.api_key = 'your-api-key'

def lookup_stock(symbol):
    # This is a local stub for the lookup_stock function.
    # Replace this with actual stock lookup logic if needed.
    stock_data = {
        "AAPL": {"price": 150.75, "change": 2.34},
        "GOOGL": {"price": 2800.50, "change": -10.25},
        "MSFT": {"price": 295.60, "change": 1.50}
    }
    return stock_data.get(symbol, None)

def call_model_with_tool():
    # Define the function to be called
    function_name = 'lookup_stock'
    function_description = {
        'name': 'lookup_stock',
        'description': 'Lookup the current stock price and change for a given symbol.',
        'parameters': {
            'type': 'object',
            'properties': {
                'symbol': {
                    'type': 'string',
                    'description': 'The stock symbol to lookup.'
                }
            },
            'required': ['symbol']
        }
    }

    # Define the tools
    tools = [
        {
            'name': function_name,
            'function': lookup_stock.__dict__
        }
    ]

    # Define the messages for the model
    messages = [
        {'role': 'system', 'content': 'You are a helpful assistant.'},
        {'role': 'user', 'content': 'What is the current stock price and change for AAPL?'},
        {
            'role': 'assistant',
            'function_call': {
                'name': function_name,
                'arguments': {
                    'symbol': 'AAPL'
                }
            }
        }
    ]

    # Call the model with the tools
    response = openai.ChatCompletion.create(
        model="gpt-4",  # Use a model that supports function calling, like gpt-4
        messages=messages,
        functions=[function_description],
        function_call={"name": function_name}
    )

    # Extract the tool result and add it to the messages
    tool_result = response['choices'][0]['message']['function_call']['arguments']
    messages.append({
        'role': 'assistant',
        'content': f"Tool output: {tool_result}"
    })

    # Call the model again with the updated messages
    final_response = openai.ChatCompletion.create(
        model="gpt-4",
        messages=messages,
        functions=[function_description],
        function_call={"name": function_name}
    )

    # Print the final answer
    print(final_response['choices'][0]['message']['content'])

# Run the function-calling round trip
call_model_with_tool()
```

### Explanation:

1. **Setting up the OpenAI API key**: Replace `'your-api-key'` with your actual OpenAI API key.
2. **Defining the `lookup_stock` function**: This is a local stub for the stock lookup function. You can replace this with actual stock lookup logic if needed.
3. **Defining the model and tools**:
   - The `function_name` and `function_description` define the function that will be called by the model.
   - The `tools` list contains the definition of the tool
